CREATE PROCEDURE [dbo].[spProductUnitCreate] @UnitCode NVARCHAR(50), @UnitName NVARCHAR(100), @UnitSymbol NVARCHAR(30), @AllowDecimal BIT, @IsBaseUnit BIT, @Description NVARCHAR(500), @CreatedByUserId INT AS BEGIN SET NOCOUNT ON; INSERT INTO [dbo].[ProductUnit] (UnitCode,UnitName,UnitSymbol,AllowDecimal,IsBaseUnit,Description,CreatedByUserId) VALUES (@UnitCode,@UnitName,ISNULL(@UnitSymbol,N''),@AllowDecimal,@IsBaseUnit,ISNULL(@Description,N''),NULLIF(@CreatedByUserId,0)); SELECT CAST(SCOPE_IDENTITY() AS INT); END;
